// MNIST inference CLI tool.
// Usage: ./cli_tool weights.json image.png
// Prints the predicted digit (0-9).
#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <vector>
#include <string>
#include <cmath>
#include "cJSON.h"
#include "lodepng.h"

static char* read_file(const char* path, size_t* len) {
    FILE* f = fopen(path, "rb");
    if (!f) return nullptr;
    fseek(f, 0, SEEK_END);
    long n = ftell(f);
    fseek(f, 0, SEEK_SET);
    char* buf = (char*)malloc(n + 1);
    if (!buf) { fclose(f); return nullptr; }
    size_t r = fread(buf, 1, n, f);
    fclose(f);
    buf[r] = '\0';
    if (len) *len = r;
    return buf;
}

// Read a 2D array (matrix) from a cJSON array-of-arrays into a flat vector.
static std::vector<float> read_matrix(cJSON* arr, int* rows, int* cols) {
    std::vector<float> out;
    *rows = cJSON_GetArraySize(arr);
    *cols = 0;
    cJSON* row;
    int ri = 0;
    cJSON_ArrayForEach(row, arr) {
        int c = cJSON_GetArraySize(row);
        if (ri == 0) *cols = c;
        cJSON* v;
        cJSON_ArrayForEach(v, row) out.push_back((float)v->valuedouble);
        ri++;
    }
    return out;
}

static std::vector<float> read_vector(cJSON* arr) {
    std::vector<float> out;
    cJSON* v;
    cJSON_ArrayForEach(v, arr) out.push_back((float)v->valuedouble);
    return out;
}

// y = W x + b, where W is [out x in] row-major, then optional ReLU.
static std::vector<float> linear(const std::vector<float>& W, const std::vector<float>& b,
                                 const std::vector<float>& x, int out_dim, int in_dim, bool relu) {
    std::vector<float> y(out_dim);
    for (int o = 0; o < out_dim; o++) {
        float acc = b[o];
        const float* wr = &W[(size_t)o * in_dim];
        for (int i = 0; i < in_dim; i++) acc += wr[i] * x[i];
        if (relu && acc < 0) acc = 0;
        y[o] = acc;
    }
    return y;
}

int main(int argc, char** argv) {
    if (argc < 3) {
        fprintf(stderr, "Usage: %s weights.json image.png\n", argv[0]);
        return 1;
    }

    size_t wlen = 0;
    char* wtext = read_file(argv[1], &wlen);
    if (!wtext) { fprintf(stderr, "Cannot read weights: %s\n", argv[1]); return 1; }
    cJSON* root = cJSON_Parse(wtext);
    if (!root) { fprintf(stderr, "Bad weights JSON\n"); return 1; }

    int r1, c1, r2, c2, r3, c3;
    std::vector<float> iw = read_matrix(cJSON_GetObjectItem(root, "input_layer.weight"), &r1, &c1);
    std::vector<float> ib = read_vector(cJSON_GetObjectItem(root, "input_layer.bias"));
    std::vector<float> hw = read_matrix(cJSON_GetObjectItem(root, "hidden_layer.weight"), &r2, &c2);
    std::vector<float> hb = read_vector(cJSON_GetObjectItem(root, "hidden_layer.bias"));
    std::vector<float> ow = read_matrix(cJSON_GetObjectItem(root, "output_layer.weight"), &r3, &c3);
    std::vector<float> ob = read_vector(cJSON_GetObjectItem(root, "output_layer.bias"));

    double mean = 0.1307, std = 0.3081;
    cJSON* meta = cJSON_GetObjectItem(root, "meta");
    if (meta) {
        cJSON* m = cJSON_GetObjectItem(meta, "mean");
        cJSON* s = cJSON_GetObjectItem(meta, "std");
        if (m) mean = m->valuedouble;
        if (s) std = s->valuedouble;
    }

    // Load and decode PNG as grayscale.
    std::vector<unsigned char> png;
    unsigned err = lodepng::load_file(png, argv[2]);
    if (err) { fprintf(stderr, "Cannot read image: %s\n", argv[2]); return 1; }
    std::vector<unsigned char> gray;
    unsigned w = 0, h = 0;
    err = lodepng::decode(gray, w, h, png, LCT_GREY, 8);
    if (err) { fprintf(stderr, "PNG decode error: %s\n", lodepng_error_text(err)); return 1; }

    // Build 784-length input vector with MNIST normalization.
    std::vector<float> x(c1);
    for (int i = 0; i < c1; i++) {
        float px = (i < (int)(w * h)) ? gray[i] : 0;
        x[i] = (float)(((px / 255.0) - mean) / std);
    }

    std::vector<float> a = linear(iw, ib, x, r1, c1, true);
    std::vector<float> b2 = linear(hw, hb, a, r2, c2, true);
    std::vector<float> logits = linear(ow, ob, b2, r3, c3, false);

    int best = 0;
    for (int i = 1; i < r3; i++) if (logits[i] > logits[best]) best = i;

    printf("%d\n", best);

    cJSON_Delete(root);
    free(wtext);
    return 0;
}
